import React from 'react'
import Container2a from './Container2a';
import Container2b from './Container2b';
import Container2c from './Container2c';
import Container2d from './Container2d';
import Container2e from './Container2e';
import Container2f from './Container2f';
import Container4a from './Container4a';



function Newarrival() {
  return (
    <div>
    <Container2a ></Container2a>
    <br></br> <br></br> <br></br>
    <Container2b></Container2b>
     <br></br> <br></br> <br></br>
    <Container2c></Container2c>
    <br></br> <br></br> <br></br>
    <br></br> <br></br> <br></br>
    <Container4a title="INFANTS"></Container4a>
    <Container2d></Container2d>
    <br></br> <br></br> <br></br>
    <br></br> <br></br> <br></br>
    <Container2e></Container2e>
    <br></br> <br></br> <br></br>
    <br></br> <br></br> <br></br>
    <Container2f></Container2f>
    <br></br> <br></br> <br></br>
    <br></br> <br></br> <br></br>
    </div>
  )
}

export default Newarrival
